import Foundation

/// Pre-composed, hand-drawn architecture stencils bundled from the community
/// System Design library (rohanp/system-design.excalidrawlib, part of
/// excalidraw/excalidraw-libraries, MIT-licensed). Because Whitespace shares the
/// Excalidraw element schema, these render natively in the rough style.
///
/// Each component's elements are normalized so the group's bounding box is
/// centered at the origin; `CanvasView.insertStencil` offsets a fresh clone to
/// the drop point, assigns new ids + a shared group id, and selects them.
struct StencilComponent: Decodable {
    let id: String
    let name: String
    let symbol: String
    let elements: [Element]
}

enum StencilLibrary {
    /// Curated System Design components, decoded once from the embedded JSON.
    static let systemDesign: [StencilComponent] = {
        guard let data = embeddedJSON.data(using: .utf8),
              let comps = try? JSONDecoder().decode([StencilComponent].self, from: data)
        else { return [] }
        return comps
    }()

    static func component(id: String) -> StencilComponent? {
        systemDesign.first { $0.id == id }
    }

